				nil,
				nil,
				handler,
			)
			assert.NoError(t, err, "Token via Authorization header should be accepted")
			assert.Equal(t, storedAuth, auth.GetAuthenticationFrom(retrievedCtx))
		})

		// Scenario 2: Token passed via cookie header (should work but fails - demonstrates bug)
		t.Run("token_via_cookie_header_should_work", func(t *testing.T) {
			var retrievedCtx context.Context
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				retrievedCtx = ctx
				return nil, nil
			}

			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{
					// Simulating a browser cookie header with the client token
					// This is how browsers would send authentication to gRPC servers
					"cookie": []string{"flipt_client_token=" + clientToken},
				},
			)

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// THIS TEST FAILS ON BUGGY CODE:
			// The token is valid and should be accepted, but the middleware
			// only checks the Authorization header, not cookies.
			// A browser would send the token in a cookie, not in the Authorization header.
			require.NoError(t, err, "Token via cookie should be accepted (REGRESSION: currently fails)")
			assert.Equal(t, storedAuth, auth.GetAuthenticationFrom(retrievedCtx), "Authentication should be extracted from cookie")
		})

		// Scenario 3: Token in custom header (fails - only Authorization header works)
		t.Run("token_via_custom_header_fails", func(t *testing.T) {
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				return nil, nil
			}

			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{
					// Try passing the token in a custom header
					"x-flipt-token": []string{clientToken},
				},
			)

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// The token is valid, but it's rejected because it's not in the Authorization header
			assert.Error(t, err, "Token via custom header should be accepted but is rejected (BUG)")
			assert.Equal(t, codes.Unauthenticated, status.Code(err))
		})
	})

	t.Run("token_creation_requires_authentication_circular_dependency", func(t *testing.T) {
		// Issue 2: No mechanism to skip authentication for specific services
		//
		// Expected: Token creation endpoint (CreateToken) should be callable without authentication
		//           to allow clients to create their first token
		// Actual: When authentication is enabled, ALL services require authentication,
		//         including the AuthenticationMethodTokenService
		//
		// This creates a circular dependency:
		// - To create a token, you need to call CreateToken
		// - But CreateToken is protected by the authentication middleware
		// - So you need a token to create a token
		// - There's no way to create the first token!
		//
		// Additionally, there's no server-level mechanism to configure which
		// services should skip authentication checks.

		t.Run("create_token_without_auth_fails", func(t *testing.T) {
			// Try to call CreateToken without authentication
			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{}, // No authentication provided
			)

			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				// If the middleware allows the request through, we would process it
				// But the middleware will reject it first
				return nil, nil
			}

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// THIS TEST FAILS ON BUGGY CODE:
			// Token creation should not require authentication (or have an unauthenticated flow),
			// but currently it does, creating a circular dependency.
			// There is no way to create the first token without already having a token.
			require.NoError(t, err, "CreateToken should be callable without authentication (REGRESSION: currently requires auth)")
		})

		// Test that shows the circular dependency clearly
		t.Run("bootstrap_token_creation_circular_dependency", func(t *testing.T) {
			// This demonstrates the problem:
			// 1. System starts with authentication required (cfg.Authentication.Required = true)
			// 2. Middleware is applied to ALL services, including token creation
			// 3. To create a token, you need to call CreateToken
			// 4. But CreateToken requires authentication (protected by middleware)
			// 5. There's no way to create the first token!
			//
			// This is typically solved by:
			// - Having an unauthenticated endpoint for creating the first token
			// - Having a separate auth service that bypasses the main middleware
			// - Having a configuration option to register services without auth
			//
			// Currently, none of these options exist in the Flipt codebase.

			// The auth middleware is applied globally in main.go:
			//   if cfg.Authentication.Required {
			//       interceptors = append(interceptors, auth.UnaryInterceptor(...))
			//   }
			//   grpcServer = grpc.NewServer(grpc_middleware.WithUnaryServerChain(interceptors...))
			//
			// This means CreateToken will ALWAYS require authentication when
			// cfg.Authentication.Required is true, with no way to override it per-service.

			assert.True(t, true, "Circular dependency confirmed: no unauthenticated way to create first token")
		})
	})

	t.Run("no_server_skip_mechanism", func(t *testing.T) {
		// Issue 3: No mechanism to skip authentication for specific server instances
		//
		// Expected: The gRPC server setup should allow configuring which services
		//           should bypass authentication checks
		// Actual: The UnaryInterceptor is applied globally to all registered services
		//         There's no way to exempt specific services or methods from authentication
		//
		// This is particularly important for services that handle delegated auth flows,
		// such as OAuth callback handlers or token creation endpoints.

		// The authentication middleware is applied at the gRPC server level in main.go:
		//
		//   if cfg.Authentication.Required {
		//       interceptors = append(interceptors, auth.UnaryInterceptor(...))
		//   }
		//   grpcServer = grpc.NewServer(grpc_middleware.WithUnaryServerChain(interceptors...))
		//   pb.RegisterFliptServer(grpcServer, srv)
		//   authrpc.RegisterAuthenticationServiceServer(grpcServer, authServer)
		//
		// This means:
		// 1. ALL registered services go through the auth middleware
		// 2. There's no way to register a service without auth
		// 3. There's no way to skip auth for specific methods

		// Verify that the middleware is applied uniformly
		t.Run("middleware_applied_to_all_methods", func(t *testing.T) {
			// Without authentication in metadata
			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{},
			)

			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				return nil, nil
			}

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// All methods fail without authentication
			assert.Error(t, err)
			assert.Equal(t, codes.Unauthenticated, status.Code(err))
		})
	})

	t.Run("expired_tokens_are_rejected", func(t *testing.T) {
		// Create an expired token to verify expiration checking still works
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authstorage.CreateAuthenticationRequest{
				Method:    authrpc.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
			},
		)
		require.NoError(t, err)

		ctx := metadata.NewIncomingContext(
			context.Background(),
			metadata.MD{
				"authorization": []string{"Bearer " + expiredToken},
			},
		)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err = auth.UnaryInterceptor(logger, authenticator)(
			ctx,
			nil,
			nil,
			handler,
		)

		// Expired tokens should be rejected
		assert.Error(t, err)
		assert.Equal(t, codes.Unauthenticated, status.Code(err))
	})
}

